local LFightIdleAniActor = LxClass("LFightIdleAniActor",nil)
----------------------------------------------------------------
-----------------------------------------------------------------
function LFightIdleAniActor:LFightIdleAniActor(obj, manager)
	---@type LFightIdleObject
	self._obj = obj

	self._manager = manager

	self._endTime = 0

	self._bWaitEnd = false
end

------------------------------------------------------------------
function LFightIdleAniActor:OnRun(time)
	if not self._bWaitEnd then return end
	if self._endTime < time then
		self:ResetIdle()
	end
end

-----------------------------------------------------------------
function LFightIdleAniActor:PlayAni(ani,loop,aniTime,timescale,mixTime)
	aniTime = aniTime or 0
	self._bWaitEnd = false
	if aniTime > 0 then
		self._endTime = self:GetTime() + aniTime
		self._bWaitEnd = true
	end
	timescale = timescale or 1
	local dpObj = self._obj:GetDpObject()
	dpObj:SetAnimationTimeScale(timescale)
	dpObj:PlayAnimation(0,ani,loop,false,mixTime)

	self._ani = ani
end
-----------------------------------------------------------------
function LFightIdleAniActor:IsAni(ani)
	return self._ani == ani
end

function LFightIdleAniActor:ResetIdle()
	self._bWaitEnd = false
	local dpObj = self._obj:GetDpObject()
	self._obj:PlayIdleAni()
end

function LFightIdleAniActor:GetTime()
	return self._manager:GetTime()
end

function LFightIdleAniActor:Pause()
	local dpObj = self._obj:GetDpObject()
	if not dpObj:IsDpValid() then
		return
	end
	dpObj:SetAnimationTimeScale(0)

end

function LFightIdleAniActor:Resume()
	local dpObj = self._obj:GetDpObject()
	if not dpObj:IsDpValid() then
		return
	end
	dpObj:SetAnimationTimeScale(1)
end

-----------------------------------------------------------------
function LFightIdleAniActor:Destroy()
	self._obj = nil
end

return LFightIdleAniActor